var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 10시간 경과","JPN":"黒い氾濫の発生から10時間経過","ENG":"10 hours since the Black Flood onset","TWN":"黑色洪災發生10小時後","DEU":"10 hours since the Black Flood onset","FRA":"10 hours since the Black Flood onset"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"섬 주민들을 대피시킬 수송기가 모자란다는 거로군.","JPN":"島民たちを避難させる輸送機が足りないということか。","ENG":"So we're short on transports to evacuate the islanders.","TWN":"沒有足夠的運輸機撤離島民。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"주민들은 끝까지 저항한다는 의사를 밝혔지만… 역시 너무 위험해요.","JPN":"住民は最後まで戦うと言っていますが……やはりあまりにも危険です。","ENG":"They say they'll stand their ground, but... it's still far too dangerous.","TWN":"雖然居民們表示會抵抗到底……但還是太危險了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"만약을 대비해 수송기를 준비해 두는 편이 좋을 것 같습니다.","JPN":"万が一に備え、輸送機を用意しておいた方がいいと思います。","ENG":"We should at least have transports ready, just in case.","TWN":"為了以防萬一，還是準備運輸機比較好。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"최고 관리자님을 모시는 메이드들과 용병들이 있지만 안심하기는 일러요.","JPN":"最高管理者様に仕えるメイドたちと傭兵がいますが、まだ安心できる段階ではありません。","ENG":"Even with the maids serving the Supreme Administrator and the mercenaries here, we can't let our guard down yet.","TWN":"雖然有侍奉最高管理者的女僕與傭兵，但還是不能放心。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"원래라면 검은 범람의 영향이 없어야 했던 섬입니다.","JPN":"本来ならこの島に黒い氾濫の影響はないはずでした。","ENG":"This island was supposed to be unaffected by the Black Flood.","TWN":"按理說這座島嶼不該受到黑色洪災的影響……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이 섬에 이 정도 규모의 침식 재난이 있었던 경우는…….","JPN":"この島に、この規模の侵食災難があったのは……","ENG":"The last time a Corruption disaster of this scale hit this island was...","TWN":"上次這種規模的侵蝕災難是……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"20년 전, 관리 실패가 터졌을 때였지.","JPN":"20年前、管理失敗の時だったな。","ENG":"Twenty years ago during the Administration Failure.","TWN":"20年前管理失敗的時候。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그때 한 소녀를 구했던 기억이 나는군.","JPN":"あの時、1人の少女を助けた記憶がある。","ENG":"I remember saving a little girl back then.","TWN":"我還記得那時救過一個女孩。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그 소녀가 지금은 한 아이의 엄마가 되었더라고요.","JPN":"その少女、今はお母さんになっていましたよ。","ENG":"She's a mother now, apparently.","TWN":"那個女孩現在已經成了某個孩子的母親了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"세월이 참 빠르지 않나요?","JPN":"時の流れは早いものですね。","ENG":"Time really flies, doesn't it?","TWN":"時間真的過得很快吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇군… 벌써 시간이 그렇게 흘렀나.","JPN":"そうだな……もうそんなに時間が経ってしまったんだな。","ENG":"I see... Has it already been that long?","TWN":"原來如此……已經過這麼久了啊。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"알파트릭스의 회장에게 전달받은 대로라면, 너와 키이라는 이제…….","JPN":"アルファトリックス会長から伝え聞いたとおりだとすると、今からお前とキーラは……","ENG":"If what the Alphatrix President said is true, then you and Kiera are now–","TWN":"按照阿爾法崔克斯會長的所說，你和琪伊拉現在已經……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님?","JPN":"シニア様？","ENG":"Senior?","TWN":"Senior？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님?!","JPN":"シニア様！？","ENG":"Senior?!","TWN":"Senior？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"토, 통신이…? 어째서……?","JPN":"つ、通信が……？　どうして……？","ENG":"Th-the signal...? Why is it...?","TWN":"通、通信……？怎麼會……？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"윽… 벨라미! 들리나?","JPN":"うっ……ベラミー！　聞こえるか？","ENG":"Ngh... Bellamy! Do you hear me?","TWN":"呃……貝拉米！聽得到嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이 지진은 대체…….","JPN":"この地震はいったい……","ENG":"This quake...","TWN":"這地震究竟……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"무슨 일이 일어난 거지?!","JPN":"何が起きている！？","ENG":"What happened?!","TWN":"發生什麼事了？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님! 대균열을 중심으로 CSE 레벨이 급격히 상승하기 시작했습니다!","JPN":"シニア！　大亀裂を中心にCSEレベルが急激に上昇し始めました！","ENG":"Senior! CSE levels around the Grand Dimension Crevice are rising rapidly!","TWN":"Senior！CSE等級開始以大峽谷為中心急速上升！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"측정 결과 CSE 레벨이 4에 도달했습니다!","JPN":"測定結果、CSEレベルは4に到達！","ENG":"Readings show CSE Level 4!","TWN":"測量結果CSE等級達到4了！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"당장 각 섹터의 전투 병력을 철수시켜!","JPN":"今すぐ各セクターの戦闘兵力を撤退させろ！","ENG":"Withdraw all combat troops from every sector!","TWN":"立刻讓各區戰鬥部隊撤離！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"격벽을 폐쇄하고 섹터 내부에서 검은 범람을 막는다!","JPN":"隔壁を閉鎖し、セクター内部で黒い氾濫を食い止める！","ENG":"Seal the bulwark! We'll hold the Black Flood from inside the sectors!","TWN":"關閉隔離牆，在區域內阻擋黑色洪災！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님! 격벽은 더 이상 검은 범람을 막을 수 없습니다.","JPN":"シニア様！　隔壁ではもう黒い氾濫を食い止めることはできません。","ENG":"Senior! The bulwark can no longer hold back the Black Flood!","TWN":"Senior！隔離牆已經無法再阻擋黑色洪災了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그, 그렇게 된다면…….","JPN":"そ、そうなると……","ENG":"I-if that happens...","TWN":"那、那樣的話……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"크라켄만 신경 써야 했으면 격벽을 폐쇄하지 않았을 거다.","JPN":"クラーケンだけを警戒するなら隔壁は閉鎖しなかった。","ENG":"If it were just Kraken, we wouldn't be sealing the bulwark at all.","TWN":"若只需要對付克拉肯，我不會下令關閉隔離牆。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 지금은 전조라는, 마왕의 진격을 눈앞에 둔 위기에 봉착해 있어.","JPN":"だが今は前兆という、魔王の進撃が目前に迫った危機に直面している。","ENG":"But this isn't just that. We're staring down the omen... the Demon Lord's advance.","TWN":"但現在我們面臨的是前兆，也是魔王逼近的危機。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};